const input = $input.first().json || {};

const raw = String(input.msgTextRaw ?? input.msgText ?? input.text ?? '').trim();
const mediaType = String(
  input.media_type ??
  input.mediaType ??
  input.type ??
  (input.isAudio ? 'audio' : '')
).trim().toLowerCase();

const isTextLike = !mediaType || mediaType === 'text';

// FIX: tsMs was stripped upstream (the 'Upsert Message API' HTTP node returns
// the API doc, dropping the session tsMs), so 'Resolve Winner' threw
// 'current tsMs is missing' and every text message failed. Derive it robustly.
let tsMs = Number(input.tsMs ?? input.ts_ms);
if (!Number.isFinite(tsMs)) {
  const iso = input.tsIso ?? input.ts_iso ?? input.timestamp ?? input.created_at;
  const parsed = iso ? Date.parse(iso) : NaN;
  tsMs = Number.isFinite(parsed) ? parsed : Date.now();
}

return [{
  json: {
    ...input,
    chatId: String(input.chatId ?? input.wa_id ?? input.phone ?? ''),
    wa_id: String(input.wa_id ?? input.chatId ?? input.phone ?? ''),
    msgId: String(input.msgId ?? input.messageId ?? input.id ?? ''),
    msgTextRaw: raw,
    media_type: mediaType,
    tsMs,
    debounceEligible: isTextLike,
    debounceWindowMs: 15000,
    debounceWindowSeconds: 15
  }
}];

const original = $('Preserve Current Turn').item.json || {};

const first = (...vals) => vals.find(v => v !== undefined && v !== null && v !== '');
const num = (v, d = null) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};
const toMs = (iso, d = null) => {
  const t = Date.parse(iso || '');
  return Number.isFinite(t) ? t : d;
};
const toIso = (ms) => new Date(num(ms, Date.now())).toISOString();
const normalizeText = (v) => String(v || '').replace(/\s+/g, ' ').trim();

const currentTsMs = num(original.tsMs, null);
const currentMsgId = String(original.msgId ?? original.messageId ?? original.id ?? '').trim();
const currentRawText = normalizeText(original.msgTextRaw ?? original.msgText ?? original.text ?? '');
const debounceWindowMs = num(original.debounceWindowMs, 45000);
const debounceEligible = original.debounceEligible !== false;
const currentMediaType = String(original.media_type ?? original.mediaType ?? '').trim().toLowerCase();

if (currentTsMs == null) {
  throw new Error('Debounce: current tsMs is missing');
}

let rows = [];
for (const item of $input.all()) {
  const j = item.json || {};
  if (Array.isArray(j.messages)) {
    rows.push(...j.messages);
  } else if (Array.isArray(j.results)) {
    rows.push(...j.results);
  } else if (Array.isArray(j.data)) {
    rows.push(...j.data);
  } else if (Array.isArray(j.rows)) {
    rows.push(...j.rows);
  } else {
    rows.push(j);
  }
}

const dedupe = new Map();

for (const row of rows) {
  const direction = String(first(row.direction, row.last_direction, 'inbound')).toLowerCase();
  const text = normalizeText(first(row.text, row.msgText, row.transcription, row.caption, ''));
  let tsMs = num(first(row.ts_ms, row.tsMs, row.last_message_ts, row.timestamp), null);
  if (tsMs == null) tsMs = toMs(first(row.ts_iso, row.tsIso, row.created_at, row.last_message_at), null);
  if (tsMs == null) continue;

  const tsIso = String(first(row.ts_iso, row.tsIso, row.created_at, row.last_message_at, '') || '');
  const mediaType = String(first(row.media_type, row.mediaType, row.type, '') || '').trim().toLowerCase();
  const id = String(first(row.id, row.msgId, row.messageId, '') || '').trim();

  const key = [id, direction, tsMs, text, mediaType, String(first(row.media_url, row.mediaUrl, ''))].join('|');

  if (!dedupe.has(key)) {
    dedupe.set(key, {
      id,
      direction,
      text,
      tsMs,
      tsIso: tsIso || toIso(tsMs),
      media_type: mediaType,
      media_url: String(first(row.media_url, row.mediaUrl, '')),
    });
  }
}

const timeline = [...dedupe.values()].sort((a, b) =>
  (a.tsMs - b.tsMs) ||
  String(a.tsIso || '').localeCompare(String(b.tsIso || '')) ||
  String(a.id || '').localeCompare(String(b.id || ''))
);

const inboundOnly = timeline.filter(m => m.direction === 'inbound');

if (!inboundOnly.length) {
  const rawFallback = String(original.msgTextRaw ?? original.msgText ?? original.text ?? '');
  const rawTsIso = String(original.tsIso || toIso(currentTsMs));
  return [{
    json: {
      ...original,
      text: rawFallback,
      msgText: rawFallback,
      msgTextRaw: rawFallback,
      debouncedText: rawFallback,
      combinedTextFinal: rawFallback,
      parts: [{
        id: currentMsgId,
        text: rawFallback,
        direction: 'inbound',
        tsMs: currentTsMs,
        tsIso: rawTsIso,
        media_type: currentMediaType,
        media_url: ''
      }],
      messageCount: 1,
      debounceCount: 1,
      debounceWinner: true,
      debounceWindowMs,
      debounceWindowSeconds: Math.round(debounceWindowMs / 1000),
      debounceBurstStartedAtMs: currentTsMs,
      debounceBurstEndedAtMs: currentTsMs,
      chatId: String(original.chatId ?? original.wa_id ?? ''),
      wa_id: String(original.wa_id ?? original.chatId ?? '')
    }
  }];
}

const latestInbound = inboundOnly[inboundOnly.length - 1];
const latestText = normalizeText(latestInbound.text);
const latestMsgId = String(latestInbound.id || '').trim();

const isWinnerById = !!currentMsgId && !!latestMsgId && currentMsgId === latestMsgId;
const isWinnerByFallback =
  latestInbound.tsMs === currentTsMs &&
  (!currentRawText || latestText === currentRawText);

if (!(isWinnerById || isWinnerByFallback)) {
  return [];
}

let burst = [latestInbound];

if (debounceEligible) {
  const latestInboundIndex = inboundOnly.findIndex(m =>
    String(m.id || '') === latestMsgId &&
    m.tsMs === latestInbound.tsMs &&
    normalizeText(m.text) === latestText
  );

  if (latestInboundIndex >= 0) {
    let anchor = inboundOnly[latestInboundIndex];

    for (let i = latestInboundIndex - 1; i >= 0; i--) {
      const prev = inboundOnly[i];

      const prevMediaType = String(prev.media_type || '').trim().toLowerCase();
      const prevIsTextLike = !prevMediaType || prevMediaType === 'text';

      if (!prevIsTextLike) break;

      const gapMs = anchor.tsMs - prev.tsMs;
      if (!Number.isFinite(gapMs) || gapMs > debounceWindowMs) break;

      burst.unshift(prev);
      anchor = prev;
    }
  }
}

const parts = burst.map(m => ({
  id: String(m.id || ''),
  text: String(m.text || '').trim(),
  direction: String(m.direction || 'inbound'),
  tsMs: Number(m.tsMs || currentTsMs),
  tsIso: String(m.tsIso || toIso(m.tsMs || currentTsMs)),
  media_type: String(m.media_type || ''),
  media_url: String(m.media_url || '')
}));

const combinedParts = parts.map(p => String(p.text || '').trim()).filter(Boolean);
const debouncedText = combinedParts.length
  ? combinedParts.join('\n')
  : String(original.msgTextRaw ?? original.msgText ?? original.text ?? '');

const burstStartMs = parts[0]?.tsMs ?? currentTsMs;
const burstEndMs = parts[parts.length - 1]?.tsMs ?? currentTsMs;
const burstEndIso = parts[parts.length - 1]?.tsIso ?? String(original.tsIso || toIso(burstEndMs));

return [{
  json: {
    ...original,
    chatId: String(original.chatId ?? original.wa_id ?? ''),
    wa_id: String(original.wa_id ?? original.chatId ?? ''),
    msgId: currentMsgId || latestMsgId,
    text: debouncedText,
    msgText: debouncedText,
    msgTextRaw: String(original.msgTextRaw ?? original.msgText ?? original.text ?? ''),
    debouncedText,
    combinedTextFinal: debouncedText,
    parts,
    messageCount: parts.length || 1,
    debounceCount: parts.length || 1,
    debounceWinner: true,
    debounceWindowMs,
    debounceWindowSeconds: Math.round(debounceWindowMs / 1000),
    debounceBurstStartedAtMs: burstStartMs,
    debounceBurstEndedAtMs: burstEndMs,
    tsMs: burstEndMs,
    tsIso: burstEndIso
  }
}];
